import React, { useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';

const AtmosphericDust = ({ isLightMode }) => {
  const dustCount = 500;

  const { positions, velocities } = useMemo(() => {
    const pos = new Float32Array(dustCount * 3);
    const vel = [];
    for (let i = 0; i < dustCount; i++) {
      pos[i * 3] = (Math.random() - 0.5) * 600;
      pos[i * 3 + 1] = (Math.random() - 0.5) * 600;
      pos[i * 3 + 2] = (Math.random() - 0.5) * 600;
      vel.push(
        new THREE.Vector3(
          (Math.random() - 0.5) * 0.05,
          -Math.random() * 0.1 - 0.02, // drifting down
          (Math.random() - 0.5) * 0.05
        )
      );
    }
    return { positions: pos, velocities: vel };
  }, []);

  useFrame((state, delta) => {
    const geom = state.scene.getObjectByName('dustSystem')?.geometry;
    if (!geom) return;

    const pos = geom.attributes.position.array;
    for (let i = 0; i < dustCount; i++) {
      const i3 = i * 3;
      pos[i3] += velocities[i].x;
      pos[i3 + 1] += velocities[i].y;
      pos[i3 + 2] += velocities[i].z;

      // Wrap around
      if (pos[i3 + 1] < -300) pos[i3 + 1] = 300;
      if (Math.abs(pos[i3]) > 300) pos[i3] *= -0.9;
    }
    geom.attributes.position.needsUpdate = true;
  });

  const dustColor = isLightMode ? '#64748b' : '#0ea5e9';
  const blendMode = isLightMode ? THREE.NormalBlending : THREE.AdditiveBlending;
  const dustOpacity = isLightMode ? 0.4 : 0.3;

  return (
    <points name="dustSystem">
      <bufferGeometry>
        <bufferAttribute attach="attributes-position" count={dustCount} array={positions} itemSize={3} />
      </bufferGeometry>
      <pointsMaterial color={dustColor} size={1.5} transparent opacity={dustOpacity} blending={blendMode} />
    </points>
  );
};

export default AtmosphericDust;

